class Solution {
    public boolean isInterleave(String s1, String s2, String s3) {
        if (s1.length() + s2.length() != s3.length()) return false;
        return dfs(s1, s2, s3, 0, 0, 0);
    }

    private boolean dfs(String s1, String s2, String s3, int i, int j, int k) {
        if (k == s3.length()) return i == s1.length() && j == s2.length();
        if (i < s1.length() && s1.charAt(i) == s3.charAt(k) && dfs(s1, s2, s3, i + 1, j, k + 1)) {
            return true;
        }
        if (j < s2.length() && s2.charAt(j) == s3.charAt(k) && dfs(s1, s2, s3, i, j + 1, k + 1)) {
            return true;
        }
        return false;
    }
}

class Solution {
    public boolean isInterleave(String s1, String s2, String s3) {
        if (s1.length() + s2.length() != s3.length()) return false;
        Boolean[][] memo = new Boolean[s1.length() + 1][s2.length() + 1];
        return dfs(s1, s2, s3, 0, 0, 0, memo);
    }

    private boolean dfs(String s1, String s2, String s3, int i, int j, int k, Boolean[][] memo) {
        if (k == s3.length()) return true;
        if (memo[i][j] != null) return memo[i][j];
        boolean valid = false;
        if (i < s1.length() && s1.charAt(i) == s3.charAt(k)) {
            valid = dfs(s1, s2, s3, i + 1, j, k + 1, memo);
        }
        if (!valid && j < s2.length() && s2.charAt(j) == s3.charAt(k)) {
            valid = dfs(s1, s2, s3, i, j + 1, k + 1, memo);
        }
        memo[i][j] = valid;
        return valid;
    }
}

class Solution {
    public boolean isInterleave(String s1, String s2, String s3) {
        if (s1.length() + s2.length() != s3.length()) return false;
        int m = s1.length(), n = s2.length();
        boolean[][] dp = new boolean[m + 1][n + 1];
        dp[0][0] = true;
        for (int i = 1; i <= m; i++) {
            dp[i][0] = dp[i - 1][0] && s1.charAt(i - 1) == s3.charAt(i - 1);
        }
        for (int j = 1; j <= n; j++) {
            dp[0][j] = dp[0][j - 1] && s2.charAt(j - 1) == s3.charAt(j - 1);
        }
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                dp[i][j] = (dp[i - 1][j] && s1.charAt(i - 1) == s3.charAt(i + j - 1))
                          || (dp[i][j - 1] && s2.charAt(j - 1) == s3.charAt(i + j - 1));
            }
        }
        return dp[m][n];
    }
}
